std::string nsTimeToDate(uint64_t t) {
  char date[40];
  uint64_t tAux = t / 1000000000ULL;
  strftime(date, sizeof(date), "%Y-%m-%d %H:%M:%S", gmtime((time_t*)&tAux));
  std::string ret(date);

  return ret;
}


