  //  std::cout << "G VERTICES ***********************" << std::endl;
  //BOOST_FOREACH( vertex_t v, vertices(gTmp) ) std::cout << gTmp[v].name << std::endl;
  //std::cout << "SAFE2REMOVE **************** END COPY GRAPH Tmp" << std::endl;

